#include<bits/stdc++.h>
using namespace std;

char a[55];

int main()
{  
	int n,len,i,j;
	scanf("%d",&n);
     for(i=1;i<=n;i++)
     {
     	scanf("%s",a);
     	if(a[0]>='a'&&a[0]<='z')
     	{
			a[0]-=32;
     	}
     	len=strlen(a);
      	for(j=1;j<=len-1;j++)
     	{
     		if(a[j]>='A'&&a[j]<='Z')
     		{
     			a[j]+=32;
     		}
     	}
     	printf("%s\n",a); 
     }
    return 0;
}
